import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                key = (name, p['id'])
                pkgs[key] = p.get('resolvedVersion', p.get('requestedVersion', ''))
    return pkgs

b = extract(baseline)
a = extract(after)
all_keys = sorted(set(b) | set(a))
changes = []
unchanged = []
for k in all_keys:
    bv, av = b.get(k, 'N/A'), a.get(k, 'N/A')
    if bv != av:
        changes.append((k[0], k[1], bv, av))
    else:
        unchanged.append((k[0], k[1], bv))

print('=== CHANGES ===')
if changes:
    for c in changes: print(f'  {c[0]:20s} {c[1]:40s} {c[2]:>10s} -> {c[3]}')
else:
    print('  None')
print()
print(f'=== UNCHANGED: {len(unchanged)} packages ===' )
for u in unchanged[:5]: print(f'  {u[0]:20s} {u[1]:40s} {u[2]:>10s}')
if len(unchanged)>5: print(f'  ... and {len(unchanged)-5} more')
"

